parameters.jsCode:
const raw = query || '{}';
let params = {};
try { params = JSON.parse(raw); } catch(e) {
  if (raw.includes('youtube')) params = {action:'youtube_play', query: raw.replace(/.*youtube/i,'').trim()};
  else if (raw.includes('spotify')) params = {action:'spotify_play', query: raw.replace(/.*spotify/i,'').trim()};
  else return JSON.stringify({success:false,error:'JSON invalido: ' + raw});
}

const APPIUM_URL = 'http://127.0.0.1:4723';
const DEVICE_ID = '5cfb06180405';

const PACKAGES = {
  youtube:'com.google.android.youtube',instagram:'com.instagram.android',
  whatsapp:'com.whatsapp',chrome:'com.android.chrome',telegram:'org.telegram.messenger',
  spotify:'com.spotify.music',gmail:'com.google.android.gm',maps:'com.google.android.apps.maps',
  camera:'com.android.camera2',settings:'com.android.settings',calculator:'com.android.calculator2',
  calendar:'com.google.android.calendar',play_store:'com.android.vending',
  tiktok:'com.zhiliaoapp.musically',twitter:'com.twitter.android',
  netflix:'com.netflix.mediaclient',zoom:'us.zoom.videomeetings',
  phone:'com.android.dialer',messages:'com.android.mms',clock:'com.android.deskclock'
};

const w = (ms) => new Promise(r => setTimeout(r, ms));

const getSessionId = async () => {
  const caps = {platformName:'Android','appium:automationName':'UiAutomator2','appium:deviceName':'Xiaomi','appium:udid':DEVICE_ID,'appium:noReset':true,'appium:newCommandTimeout':120,'appium:adbExecTimeout':30000,'appium:skipServerInstallation':false};
  const res = await helpers.httpRequest({method:'POST',url:`${APPIUM_URL}/session`,headers:{'Content-Type':'application/json'},body:{capabilities:{alwaysMatch:caps}}});
  return res?.value?.sessionId || res?.sessionId;
};

const closeSession = async (sid) => {
  await helpers.httpRequest({method:'DELETE',url:`${APPIUM_URL}/session/${sid}`,headers:{'Content-Type':'application/json'}}).catch(()=>{});
};

const getPageSource = async (base) => {
  const res = await helpers.httpRequest({method:'GET',url:`${base}/source`,headers:{'Content-Type':'application/json'}});
  return res?.value || '';
};

const findElementCoords = (xml, searchText) => {
  const patterns = [
    new RegExp(`text="[^"]*${searchText}[^"]*"[^>]*bounds="\\[(\\d+),(\\d+)\\]\\[(\\d+),(\\d+)\\]"`, 'i'),
    new RegExp(`content-desc="[^"]*${searchText}[^"]*"[^>]*bounds="\\[(\\d+),(\\d+)\\]\\[(\\d+),(\\d+)\\]"`, 'i')
  ];
  for (const pattern of patterns) {
    const match = xml.match(pattern);
    if (match) {
      const x1=parseInt(match[1]),y1=parseInt(match[2]),x2=parseInt(match[3]),y2=parseInt(match[4]);
      return {x:Math.floor((x1+x2)/2),y:Math.floor((y1+y2)/2),found:true};
    }
  }
  return {found:false};
};

const doTap = async (base,x,y) => {
  await helpers.httpRequest({method:'POST',url:`${base}/actions`,headers:{'Content-Type':'application/json'},body:{actions:[{type:'pointer',id:'finger1',parameters:{pointerType:'touch'},actions:[{type:'pointerMove',duration:0,x,y},{type:'pointerDown',button:0},{type:'pause',duration:80},{type:'pointerUp',button:0}]}]}});
};

const doType = async (base,text) => {
  for (const c of text) {
    await helpers.httpRequest({method:'POST',url:`${base}/actions`,headers:{'Content-Type':'application/json'},body:{actions:[{type:'key',id:'keyboard',actions:[{type:'keyDown',value:c},{type:'keyUp',value:c}]}]}});
    await w(Math.floor(Math.random()*80)+40);
  }
};

const pressKeycode = async (base,keycode) => {
  await helpers.httpRequest({method:'POST',url:`${base}/execute/sync`,headers:{'Content-Type':'application/json'},body:{script:'mobile: pressKey',args:[{keycode}]}});
};

const openApp = async (base,packageName) => {
  const pkg = PACKAGES[packageName.toLowerCase()] || packageName;
  await helpers.httpRequest({method:'POST',url:`${base}/appium/device/activate_app`,headers:{'Content-Type':'application/json'},body:{appId:pkg}});
  await w(2500);
  return pkg;
};

try {
  const sessionId = await getSessionId();
  if (!sessionId) return JSON.stringify({success:false,error:'No se pudo crear sesión Appium.'});
  const base = `${APPIUM_URL}/session/${sessionId}`;
  let result = {};

  switch(params.action) {
    case 'open_app': {
      const pkg = await openApp(base, params.package||params.app||'com.android.settings');
      result = {success:true,action:'open_app',opened:pkg}; break;
    }
    case 'tap': {
      await doTap(base,params.x||540,params.y||960); await w(400);
      result = {success:true,action:'tap',x:params.x,y:params.y}; break;
    }
    case 'type_text': {
      await doType(base,params.text||'');
      result = {success:true,action:'type_text',typed:params.text}; break;
    }
    case 'press_key': {
      const keycodes = {back:4,home:3,recent:187,enter:66,volume_up:24,volume_down:25,mute:164,power:26,media_play_pause:85,media_next:87,media_prev:88};
      const kc = keycodes[params.key]||4;
      await pressKeycode(base,kc); await w(300);
      result = {success:true,action:'press_key',key:params.key}; break;
    }
    case 'get_battery': {
      const bat = await helpers.httpRequest({method:'POST',url:`${base}/execute/sync`,headers:{'Content-Type':'application/json'},body:{script:'mobile: batteryInfo',args:[]}});
      const level = bat?.value?.level ?? 'desconocido';
      const state = bat?.value?.state===2?'cargando':'descargando';
      result = {success:true,action:'get_battery',level:`${Math.round(level*100)}%`,state}; break;
    }
    case 'adjust_volume': {
      const kc = params.direction==='up'?24:25;
      const steps = params.steps||1;
      for(let i=0;i<steps;i++){await pressKeycode(base,kc);await w(200);}
      result = {success:true,action:'adjust_volume',direction:params.direction,steps}; break;
    }
    case 'youtube_play': {
      await openApp(base,'youtube'); await w(3000);
      let xml = await getPageSource(base);
      let searchBtn = findElementCoords(xml,'Search');
      if(searchBtn.found){await doTap(base,searchBtn.x,searchBtn.y);await w(1500);}
      else{await doTap(base,950,72);await w(1500);}
      await doType(base,params.query||'music'); await w(800);
      await pressKeycode(base,66); await w(3000);
      xml = await getPageSource(base);
      const firstResult = findElementCoords(xml,params.query?.split(' ')[0]||'');
      if(firstResult.found){await doTap(base,firstResult.x,firstResult.y);}
      else{await doTap(base,540,400);}
      result = {success:true,action:'youtube_play',query:params.query,status:'reproduciendo'}; break;
    }
    case 'spotify_play': {
      await openApp(base,'spotify'); await w(3000);
      let xml = await getPageSource(base);
      let searchTab = findElementCoords(xml,'Search');
      if(!searchTab.found) searchTab = findElementCoords(xml,'Buscar');
      if(searchTab.found){await doTap(base,searchTab.x,searchTab.y);await w(1500);}
      xml = await getPageSource(base);
      const sf = findElementCoords(xml,'Artists, songs, or podcasts');
      const sf2 = findElementCoords(xml,'Artistas, canciones');
      const field = sf.found?sf:sf2;
      if(field.found){await doTap(base,field.x,field.y);}else{await doTap(base,540,160);}
      await w(1000); await doType(base,params.query||''); await w(800);
      await pressKeycode(base,66); await w(2500);
      xml = await getPageSource(base);
      const track = findElementCoords(xml,params.query?.split(' ')[0]||'');
      if(track.found){await doTap(base,track.x,track.y);await w(1000);
        xml = await getPageSource(base);
        const playBtn = findElementCoords(xml,'Play');
        if(playBtn.found) await doTap(base,playBtn.x,playBtn.y);
      }else{await doTap(base,540,350);}
      result = {success:true,action:'spotify_play',query:params.query,status:'reproduciendo'}; break;
    }
    case 'read_notifications': {
      await helpers.httpRequest({method:'POST',url:`${base}/execute/sync`,headers:{'Content-Type':'application/json'},body:{script:'mobile: openNotifications',args:[]}});
      await w(1500);
      const nxml = await getPageSource(base);
      const notifs = [...nxml.matchAll(/text="([^"]{5,})"/g)].map(m=>m[1]).filter(t=>!['OK','Cancel','Clear all'].includes(t)).slice(0,10);
      await pressKeycode(base,4);
      result = {success:true,action:'read_notifications',notifications:notifs,count:notifs.length}; break;
    }
    default:
      result = {success:false,error:`Acción desconocida: ${params.action}`};
  }

  await closeSession(sessionId);
  return JSON.stringify(result);
} catch(e) {
  return JSON.stringify({success:false,error:e.message});
}

// 📦 CONTEXT INJECTOR — pega esto en los 4 clusters
const agentOutput = $input.first().json;
const trigger = $('When Executed by Another Workflow').first().json;

return [{
  json: {
    // ─── OUTPUT DEL AGENTE ───
    output: agentOutput.output || agentOutput.text || agentOutput.response || '',

    // ─── CONTEXTO ORIGINAL COMPLETO ───
    channel: trigger.channel || 'telegram',

    // ─── TELEGRAM ───
    message: trigger.message || null,
    callback_query: trigger.callback_query || null,

    // ─── WHATSAPP ───
    remoteJid: trigger.remoteJid || null,
    messageId: trigger.messageId || null,

    // ─── SESSION ───
    _sessionId: trigger._sessionId || trigger.message?.chat?.id?.toString() || trigger.chatId || 'fallback_session',
    chatId: trigger.message?.chat?.id || trigger.callback_query?.message?.chat?.id || trigger.chatId || '',

    // ─── CLUSTER INFO ───
    _cluster: trigger._cluster || 'UNKNOWN',
    _isCallback: trigger._isCallback || false,
  }
}];
